final:
module RefModule(
	input 	clk,
	input 	clear,
	input 	set,
	output reg [15:0] Q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clear or posedge dbg_halt)
begin
	if (clear)
		Q <= 16'b0000000000000000;
	else if (set)
		Q <= 16'b1111111111111111;
end

endmodule
